import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface TopPick {
  title: string;
  rating: number;
  genre: string;
  runtime: number;
}

interface MovieData {
  topPicks: TopPick[];
}

export default function Widget() {
  const movieData = response.data as MovieData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1F2937' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#F59E0B' }}>
            Top Picks
          </Typography>
          {movieData.topPicks.map((pick) => (
            <Box key={pick.title} sx={{ mb: 1 }}>
              <Typography variant="body1" sx={{ color: '#F3F4F6', fontWeight: 500 }}>
                {pick.title}
              </Typography>
              <Stack direction="row" spacing={0.5}>
                <Chip label={`${pick.rating}/10`} sx={{ fontSize: '11px', color: '#E5E7EB', bgcolor: '#2563EB' }} />
                <Chip label={pick.genre} sx={{ fontSize: '11px', color: '#E5E7EB', bgcolor: '#2563EB' }} />
                <Chip label={`${pick.runtime} mins`} sx={{ fontSize: '11px', color: '#E5E7EB', bgcolor: '#2563EB' }} />
              </Stack>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
